var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최고 관리자 권한 확인. 함선 동결을 해제합니다.</color>","JPN":"<color=#ffd34c>最高管理者権限確認。艦船の凍結を解除します。</color>","ENG":"<color=#ffd34c>Supreme Administrator authorization confirmed. Removing cryostasis.</color>","TWN":"<color=#ffd34c>確認最高管理者權限，解除艦船凍結。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떤가, 내 실력이? 이거 정말 기술자로 전직해도 되겠군.","JPN":"見たか？　本気でエンジニアへの転職を考えるべきかもな。","ENG":"So what do you think of that? Maybe I could really be an engineer for a living.","TWN":"怎麼樣，我的實力？我這樣可以轉職成真正的技術人員吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"평범하게 관리자 권한으로 해제하셨으면서 말씀은 잘하시는군요.","JPN":"普通に管理者権限で解除しておきながら、\\nその自画自賛ぶりはさすがですね。","ENG":"Oh, please. All you did was use your Administrator authority to access the system.","TWN":"您只是很普通地用管理者權限解除凍結而已，還這麼敢說啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"누가 들으면 해킹이라도 한 줄 알겠습니다.","JPN":"誰かが聞いていれば、本当にハッキングでもしたのかと思われそうです。","ENG":"It's not like you actually did any hacking.","TWN":"別人聽了，還以為你是駭客呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가끔은 칭찬이라도 해 주지 그러나. 우리 부사장은 너무 딱딱해서 문제야.","JPN":"たまには褒めてくれたっていいだろ。\\nわが社の副社長はそう堅苦しいからいけないんだ。","ENG":"You could really work on complimenting people. You're too stiff for your own good, Vice President.","TWN":"偶爾也稱讚我一下嘛，我們副總的問題就是太死板了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"말이 나와서 말인데, 우리 회사 직원들은 다들 한 성질 해서 말이지......","JPN":"ついでに言えば、わが社の社員は揃いも揃って\\nジョークの通じない怒りん坊だらけで……","ENG":"Speaking of which, all our employees seem to have quite the temper...","TWN":"說到這個，我們公司的員工都很有個性呢……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이번 일이 잘 끝나면 한 번 고려해 보기로 하죠.","JPN":"その話はこの件が片付いた後でじっくり聞かせていただきます。","ENG":"I'll consider it once we make it out of here alive.","TWN":"如果這次的事情順利解決，我會考慮一下的。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그보다, 주변이 갑자기 조용해진 것 같네요.","JPN":"それより、周りが急に静かになりましたね。","ENG":"By the way, it seems awfully quiet all of a sudden.","TWN":"話說回來，周圍好像突然變得安靜了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"예상대로군.","JPN":"予想通りだな。","ENG":"Yeah, I totally saw this coming.","TWN":"果然跟預料中的一樣。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......네, 예상대로군요.","JPN":"……はい、予想通りです。","ENG":"Indeed.","TWN":"……是啊，跟預料中的一樣。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"드디어......","JPN":"ようやく……","ENG":"Finally...","TWN":"終於……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"드디어 안에 들어갈 수 있게 됐어......!","JPN":"ようやく内部に踏み込めるのだな……！","ENG":"I can finally enter the ship!","TWN":"終於能進入內部了……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 약속대로 방주선의 동결은 해제했네.","JPN":"ああ。約束通り箱舟の凍結は解除してある。","ENG":"Indeed. As promised, I've undone the stasis of the Ark.","TWN":"是的，按照約定，我把方舟的凍結解除了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"훌륭하군!","JPN":"見事な働きだ！","ENG":"Excellent!","TWN":"太了不起了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"자, 비켜라. 안으로 들어가 봐야겠어.","JPN":"さあ、どけ。さっそく中に入らせてもらう。","ENG":"Now step aside! I've got to get in there.","TWN":"快，讓開，我要進去看看。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아. 그 전에 잠시만 기다려 주게.","JPN":"あっ、少し待ってくれ。その前に……","ENG":"Oh, by the way. Why don't you hang on for just a sec.","TWN":"喔，不過在那之前，妳得先等一下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"사사건건 걸리적거리는군! 기다릴 시간 따윈 없다!","JPN":"いちいち癇に障る奴め！　待つ暇などない！","ENG":"Why do you have to keep getting in the way?! I don't have time to wait!","TWN":"你真是每件事都要妨礙我耶！我沒有時間等了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};